CREATE OR REPLACE FUNCTION f_unaccent(text)
RETURNS text LANGUAGE 'sql' COST 100 IMMUTABLE PARALLEL UNSAFE
AS $BODY$ SELECT unaccent('unaccent', $1) $BODY$;

